module sobel_edge_detector(
    input [7:0] pixel00, input [7:0] pixel01, input [7:0] pixel02,
    input [7:0] pixel10, input [7:0] pixel11, input [7:0] pixel12,
    input [7:0] pixel20, input [7:0] pixel21, input [7:0] pixel22,
    output [10:0] gradient_magnitude
);
    wire signed [10:0] Gx;
    wire signed [10:0] Gy;

      wire _n01 = (pixel00 * -1) + (pixel01 * 0) + (pixel02 * 1) +
                (pixel10 * -2) + (pixel11 * 0) + (pixel12 * 2) +
                (pixel20 * -1) + (pixel21 * 0)[0] ^ (pixel22 * 1)[0];
  wire _c01 = (pixel00 * -1) + (pixel01 * 0) + (pixel02 * 1) +
                (pixel10 * -2) + (pixel11 * 0) + (pixel12 * 2) +
                (pixel20 * -1) + (pixel21 * 0)[0] & (pixel22 * 1)[0];
  wire _n02 = (pixel00 * -1) + (pixel01 * 0) + (pixel02 * 1) +
                (pixel10 * -2) + (pixel11 * 0) + (pixel12 * 2) +
                (pixel20 * -1) + (pixel21 * 0)[1] ^ (pixel22 * 1)[1] ^ _c01;
  wire _c02 = ((pixel00 * -1) + (pixel01 * 0) + (pixel02 * 1) +
                (pixel10 * -2) + (pixel11 * 0) + (pixel12 * 2) +
                (pixel20 * -1) + (pixel21 * 0)[1] & (pixel22 * 1)[1]) | ((pixel00 * -1) + (pixel01 * 0) + (pixel02 * 1) +
                (pixel10 * -2) + (pixel11 * 0) + (pixel12 * 2) +
                (pixel20 * -1) + (pixel21 * 0)[1] & _c01) | ((pixel22 * 1)[1] & _c01);
  wire _n03 = (pixel00 * -1) + (pixel01 * 0) + (pixel02 * 1) +
                (pixel10 * -2) + (pixel11 * 0) + (pixel12 * 2) +
                (pixel20 * -1) + (pixel21 * 0)[2] ^ (pixel22 * 1)[2] ^ _c02;
  wire _c03 = ((pixel00 * -1) + (pixel01 * 0) + (pixel02 * 1) +
                (pixel10 * -2) + (pixel11 * 0) + (pixel12 * 2) +
                (pixel20 * -1) + (pixel21 * 0)[2] & (pixel22 * 1)[2]) | ((pixel00 * -1) + (pixel01 * 0) + (pixel02 * 1) +
                (pixel10 * -2) + (pixel11 * 0) + (pixel12 * 2) +
                (pixel20 * -1) + (pixel21 * 0)[2] & _c02) | ((pixel22 * 1)[2] & _c02);
  wire _n04 = (pixel00 * -1) + (pixel01 * 0) + (pixel02 * 1) +
                (pixel10 * -2) + (pixel11 * 0) + (pixel12 * 2) +
                (pixel20 * -1) + (pixel21 * 0)[3] ^ (pixel22 * 1)[3] ^ _c03;
  wire _c04 = ((pixel00 * -1) + (pixel01 * 0) + (pixel02 * 1) +
                (pixel10 * -2) + (pixel11 * 0) + (pixel12 * 2) +
                (pixel20 * -1) + (pixel21 * 0)[3] & (pixel22 * 1)[3]) | ((pixel00 * -1) + (pixel01 * 0) + (pixel02 * 1) +
                (pixel10 * -2) + (pixel11 * 0) + (pixel12 * 2) +
                (pixel20 * -1) + (pixel21 * 0)[3] & _c03) | ((pixel22 * 1)[3] & _c03);
  assign Gx = {_n01, _n02, _n03, _n04};

    assign Gy = (pixel00 * -1) + (pixel01 * -2) + (pixel02 * -1) +
                (pixel10 * 0) + (pixel11 * 0) + (pixel12 * 0) +
                (pixel20 * 1) + (pixel21 * 2) + (pixel22 * 1);

    assign gradient_magnitude = (Gx < 0 ? -Gx : Gx) + (Gy < 0 ? -Gy : Gy);
endmodule
